function MiniPlayer({ open, setOpen, trackIdx, setTrackIdx, T }) {
  const track = TRACKS[trackIdx]
  const prev = () => setTrackIdx(i => (i - 1 + TRACKS.length) % TRACKS.length)
  const next = () => setTrackIdx(i => (i + 1) % TRACKS.length)

  return (
    <div style={{
      position:'fixed', bottom:0, left:0, right:0, zIndex:99999,
      background: T.surf,
      borderTop:`2px solid ${BRAND.amber}`,
      display:'flex', alignItems:'center',
      padding:'0 20px',
      height: open ? 56 : 38,
      transition:'height 0.2s',
      boxShadow:'0 -4px 24px rgba(0,0,0,0.5)',
      transform:'translateZ(0)',
    }}>
      {/* Logo Suno + titre */}
      <div style={{ display:'flex', alignItems:'center', gap:10, flex:1, minWidth:0 }}>
        <div style={{
          width:28, height:28, borderRadius:6, flexShrink:0,
          background:`linear-gradient(135deg, ${BRAND.purple}, ${BRAND.orange})`,
          display:'flex', alignItems:'center', justifyContent:'center',
          fontSize:'0.8rem', fontWeight:700, color:'#fff',
        }}>♪</div>
        {open && (
          <div style={{ minWidth:0 }}>
            <div style={{ fontSize:'0.72rem', color:T.text, fontWeight:600, whiteSpace:'nowrap', overflow:'hidden', textOverflow:'ellipsis' }}>
              GaufreGentille · Track {trackIdx + 1}/{TRACKS.length}
            </div>
            <div style={{ fontSize:'0.62rem', color:T.faint }}>Kissa Soko playlist · Suno</div>
          </div>
        )}
        {!open && (
          <span style={{ fontSize:'0.7rem', color:T.dim }}>GaufreGentille · {trackIdx + 1}/{TRACKS.length}</span>
        )}
      </div>

      {/* Controls */}
      {open && (
        <div style={{ display:'flex', alignItems:'center', gap:8, marginRight:16 }}>
          <button onClick={prev} style={{ background:'none', border:'none', color:T.dim, fontSize:'1rem', cursor:'pointer', padding:'4px 6px' }}>⏮</button>
          <a href={track.url} target="_blank" rel="noopener noreferrer"
            style={{ background:BRAND.amber, color:'#000', fontSize:'0.72rem', fontWeight:700, padding:'6px 14px', borderRadius:20, textDecoration:'none', display:'flex', alignItems:'center', gap:5 }}>
            ▶ Ecouter sur Suno
          </a>
          <button onClick={next} style={{ background:'none', border:'none', color:T.dim, fontSize:'1rem', cursor:'pointer', padding:'4px 6px' }}>⏭</button>
        </div>
      )}

      {/* Track dots */}
      {open && (
        <div style={{ display:'flex', gap:4, marginRight:16, flexWrap:'wrap', maxWidth:120 }}>
          {TRACKS.map((_, i) => (
            <div key={i} onClick={() => setTrackIdx(i)} style={{
              width:6, height:6, borderRadius:'50%', cursor:'pointer',
              background: i === trackIdx ? BRAND.amber : T.faint,
              transition:'background 0.15s',
            }} />
          ))}
        </div>
      )}

      {/* Toggle */}
      <button onClick={() => setOpen(o => !o)} style={{
        background:'none', border:`1px solid ${T.border2}`,
        color:T.dim, fontSize:'0.65rem', fontWeight:600,
        padding:'4px 10px', borderRadius:6, cursor:'pointer',
        fontFamily:'inherit', letterSpacing:'0.05em',
        flexShrink:0,
      }}>
        {open ? '▼ Reduire' : '♪ Musique'}
      </button>
    </div>
  )
}

export default function App() {
  const [tab, setTab]         = useState('news')
  const [dark, setDark]       = useState(true)
  const [news, setNews]       = useState([])
  const [science, setSci]     = useState([])
  const [reddit, setReddit]   = useState([])
  const [markets, setMarkets] = useState([])
  const [loading, setLoading] = useState(true)
  const [mktTime, setMktTime] = useState('--')
  const [error, setError]     = useState(null)
  const [lastRefresh, setLastRefresh] = useState(null)
  const [instaFilter, setInstaFilter] = useState('Tous')
  const [community, setCommunity]     = useState([])
  const [commLoading, setCommLoading] = useState(false)
  const [gearItems, setGearItems]     = useState([])
  const [gearLoading, setGearLoading] = useState(false)
  const [showVitality, setShowVitality] = useState(false)
  const [gear, setGear]         = useState([])

  const T = dark ? DARK : LIGHT

  const today = new Date()
  const DAYS   = ['Dimanche','Lundi','Mardi','Mercredi','Jeudi','Vendredi','Samedi']
  const MONTHS = ['janvier','fevrier','mars','avril','mai','juin','juillet','aout','septembre','octobre','novembre','decembre']
  const dateStr = `${DAYS[today.getDay()]} ${today.getDate()} ${MONTHS[today.getMonth()]} ${today.getFullYear()}`

  const fetchAll = useCallback(async () => {
    setLoading(true)
    setError(null)
    try {
      const [contentRes, mktRes] = await Promise.all([
        fetch('/.netlify/functions/get-news'),
        fetch('/.netlify/functions/get-markets'),
      ])
      const content = await contentRes.json()
      const mkt     = await mktRes.json()
      if (content.news)    setNews(content.news)
      if (content.science) setSci(content.science)
      if (content.community) setReddit(content.community)
      else if (content.reddit)  setReddit(content.reddit)
      if (content.gear)    setGear(content.gear)
      if (mkt.markets)     setMarkets(mkt.markets)
      if (mkt.updatedAt)   setMktTime(mkt.updatedAt)
      setLastRefresh(new Date().toLocaleTimeString('fr-FR',{hour:'2-digit',minute:'2-digit'}))
    } catch(e) {
      setError('Erreur de chargement. Verifie ta connexion.')
    } finally {
      setLoading(false)
    }
  }, [])

  useEffect(() => { fetchAll() }, [fetchAll])

  const fetchCommunity = useCallback(async () => {
    setCommLoading(true)
    try {
      const res  = await fetch('/.netlify/functions/get-sprudge')
      const data = await res.json()
      if (data.tiles && data.tiles.length > 0) {
        setCommunity(data.tiles)
      }
    } catch(e) {
      console.error('Community fetch error:', e)
    }
    setCommLoading(false)
  }, [])

  useEffect(() => { fetchCommunity() }, [fetchCommunity])

  const fetchGear = useCallback(async () => {
    setGearLoading(true)
    try {
      const res  = await fetch('/.netlify/functions/get-gear')
      const data = await res.json()
      if (data.gear && data.gear.length > 0) setGearItems(data.gear)
    } catch(e) { console.error('Gear fetch error:', e) }
    setGearLoading(false)
  }, [])
  useEffect(() => { fetchGear() }, [fetchGear])


  return (
    <div style={{ background:T.bg, minHeight:'100vh', color:T.text, fontFamily:"Inter,-apple-system,system-ui,sans-serif", fontWeight:500, fontSize:17, transition:'background 0.3s, color 0.3s', position:'relative' }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700&display=swap'); @keyframes fadeUp{from{opacity:0;transform:translateY(12px)}to{opacity:1;transform:translateY(0)}}
        @keyframes spin{to{transform:rotate(360deg)}}
        *{box-sizing:border-box;margin:0;padding:0;} a{color:inherit;} ::-webkit-scrollbar{width:6px;} ::-webkit-scrollbar-track{background:transparent;} ::-webkit-scrollbar-thumb{background:${T.border2};border-radius:3px;}
      `}</style>

      {/* TOPBAR */}
      <div style={{ background:T.surf, borderBottom:`1px solid ${T.border}`, padding:'0 20px', height:54, display:'flex', alignItems:'center', justifyContent:'space-between', position:'sticky', top:0, zIndex:100, backdropFilter:'blur(12px)' }}>
        <div style={{ display:'flex', alignItems:'center', gap:12 }}>
          {/* Logo */}
          <div style={{ display:'flex', alignItems:'center', gap:12 }}>
            <img src="/logo.png" alt="Kissa Soko" style={{ height:36, width:'auto', display:'block', borderRadius:10 }} />
            <div style={{ fontSize:11, color:T.dim, letterSpacing:'0.08em', textTransform:'uppercase', fontWeight:500 }}>by GaufreGentille · Actu Cafe</div>
          </div>
        </div>
        <div style={{ display:'flex', alignItems:'center', gap:10 }}>
          <span style={{ fontSize:'0.63rem', color:T.faint }}>{dateStr}</span>
          {lastRefresh && <span style={{ fontSize:'0.62rem', color:T.faint, display:'flex', alignItems:'center', gap:4 }}>
            <span style={{ width:5, height:5, borderRadius:'50%', background:'#7a9e78', display:'inline-block' }} />{lastRefresh}
          </span>}
          <button onClick={fetchAll} style={{ background:T.surf2, border:`1px solid ${T.border2}`, color:T.dim, fontSize:'0.72rem', padding:'5px 11px', borderRadius:7, cursor:'pointer', fontFamily:'inherit', transition:'all 0.15s' }}>
            ↺
          </button>
          {/* Dark/Light toggle */}
          <button onClick={()=>setDark(!dark)} style={{ background: dark ? BRAND.yellow+'22' : BRAND.purple+'22', border:`1px solid ${dark ? BRAND.yellow+'44' : BRAND.purple+'44'}`, color: dark ? BRAND.yellow : BRAND.purple, fontSize:'0.72rem', padding:'5px 11px', borderRadius:7, cursor:'pointer', fontFamily:'inherit', fontWeight:600, transition:'all 0.2s' }}>
            {dark ? '☀ Clair' : '☾ Sombre'}
          </button>
        </div>
      </div>

      {/* MARKETS STRIP */}
      <div style={{ background:T.surf, borderBottom:`2px solid ${BRAND.yellow}22`, display:'flex', overflowX:'auto', padding:'0 24px', minHeight:64 }}>
        {(markets.length ? markets : [
          {label:'Arabica ICE',val:'--',unit:'c/lb',chg:'',up:true},
          {label:'Robusta ICE',val:'--',unit:'$/t', chg:'',up:false},
          {label:'EUR/USD',    val:'--',unit:'',    chg:'',up:true},
          {label:'BRL/USD',   val:'--',unit:'',    chg:'',up:true},
        ]).map((m,i) => (
          <div key={i} style={{ padding:'9px 24px 9px 0', minWidth:140, borderRight:`1px solid ${T.border}`, flexShrink:0 }}>
            <div style={{ fontSize:11, textTransform:'uppercase', letterSpacing:'0.1em', color:T.dim, marginBottom:5, fontWeight:600 }}>{m.label}</div>
            <div style={{ display:'flex', alignItems:'baseline', gap:7 }}>
              <span style={{ fontSize:'1.25rem', fontWeight:700, color:T.text }}>
                {m.val}{m.unit && <span style={{ fontSize:9, color:T.faint, marginLeft:3 }}>{m.unit}</span>}
              </span>
              {m.chg && <span style={{ fontSize:'0.85rem', color:m.up ? '#7cb87c' : '#c07070', fontWeight:700 }}>{m.up ? '▲' : '▼'}{m.chg}</span>}
            </div>
            {m.note && <div style={{ fontSize:8, color:T.faint, marginTop:2 }}>{m.note}</div>}
          </div>
        ))}
        <div style={{ padding:'9px 0 9px 20px', minWidth:80, flexShrink:0 }}>
          <div style={{ fontSize:11, textTransform:'uppercase', letterSpacing:'0.1em', color:T.dim, marginBottom:5, fontWeight:600 }}>Mis a jour</div>
          <div style={{ fontSize:'1.1rem', color:T.text, fontWeight:700 }}>{mktTime}</div>
        </div>
        {/* Vitality logo button */}
        <div style={{ padding:'9px 0 9px 16px', flexShrink:0, display:'flex', alignItems:'center' }}>
          <button onClick={() => setShowVitality(v => !v)} style={{
            background:'none', border:'none', cursor:'pointer', padding:4, borderRadius:8,
            opacity: showVitality ? 1 : 0.6, transition:'all 0.2s',
            transform: showVitality ? 'scale(1.1)' : 'scale(1)',
          }} title="Team Vitality CS2">
            <img src="/vitality-logo.webp" alt="Team Vitality" style={{ width:32, height:32, borderRadius:6, objectFit:'cover', display:'block' }} />
          </button>
        </div>
      </div>

      {/* VITALITY PANEL */}
      {showVitality && (
        <div style={{ background:T.surf, borderBottom:`1px solid ${BRAND.amber}44`, padding:'20px', animation:'fadeUp 0.2s ease both' }}>
          <div>
            {/* Header */}
            <div style={{ display:'flex', alignItems:'center', gap:16, marginBottom:20, paddingBottom:14, borderBottom:`1px solid ${T.border}` }}>
              <img src="/vitality-logo.webp" alt="Team Vitality" style={{ width:48, height:48, borderRadius:10, flexShrink:0, objectFit:'cover' }} />
              <div>
                <div style={{ fontSize:'1.1rem', fontWeight:700, color:T.text }}>Team Vitality · CS2</div>
                <div style={{ fontSize:'0.75rem', color:T.dim }}>Rang mondial #1 · apEX · ropz · ZywOo · flameZ · mezii</div>
              </div>
              <a href="https://bo3.gg/teams/vitality/matches" target="_blank" rel="noopener noreferrer"
                style={{ marginLeft:'auto', fontSize:'0.7rem', color:BRAND.slate, textDecoration:'none', flexShrink:0 }}>
                Tous les matchs →
              </a>
            </div>

            <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:16 }}>
              {/* Derniers résultats */}
              <div style={{ background:T.surf, border:`1px solid ${T.border}`, borderRadius:12, padding:'16px 18px' }}>
                <div style={{ fontSize:10, textTransform:'uppercase', letterSpacing:'0.15em', color:T.faint, fontWeight:600, marginBottom:14 }}>Derniers résultats</div>
                {[
                  { date:'15 mai', event:'IEM Atlanta 2026', opp:'Natus Vincere', score:'0 - 2', win:false },
                  { date:'13 mai', event:'IEM Atlanta 2026', opp:'B8', score:'2 - 0', win:true },
                  { date:'03 mai', event:'BLAST Rivals Spring', opp:'Finale', score:'1er', win:true },
                  { date:'23 mars', event:'BLAST Rotterdam', opp:'PARIVISION', score:'2 - 0', win:true },
                  { date:'21 mars', event:'BLAST Rotterdam', opp:'The MongolZ', score:'2 - 0', win:true },
                ].map((m, i) => (
                  <div key={i} style={{ display:'flex', alignItems:'center', gap:10, padding:'8px 0', borderBottom: i < 4 ? `1px solid ${T.border}` : 'none' }}>
                    <div style={{ width:32, height:32, borderRadius:6, background: m.win ? '#7cb87c22' : '#be6f6f22', border:`1px solid ${m.win ? '#7cb87c44' : '#be6f6f44'}`, display:'flex', alignItems:'center', justifyContent:'center', fontSize:'0.75rem', fontWeight:700, color: m.win ? '#7cb87c' : '#be6f6f', flexShrink:0 }}>
                      {m.win ? 'W' : 'L'}
                    </div>
                    <div style={{ flex:1, minWidth:0 }}>
                      <div style={{ fontSize:'0.82rem', fontWeight:600, color:T.text, whiteSpace:'nowrap', overflow:'hidden', textOverflow:'ellipsis' }}>{m.opp}</div>
                      <div style={{ fontSize:'0.68rem', color:T.faint }}>{m.event}</div>
                    </div>
                    <div style={{ fontSize:'0.82rem', fontWeight:700, color: m.win ? '#7cb87c' : '#be6f6f', flexShrink:0 }}>{m.score}</div>
                    <div style={{ fontSize:'0.65rem', color:T.faint, flexShrink:0 }}>{m.date}</div>
                  </div>
                ))}
              </div>

              {/* Prochains matchs + stats */}
              <div style={{ display:'flex', flexDirection:'column', gap:14 }}>
                {/* Prochains matchs */}
                <div style={{ background:T.surf, border:`1px solid ${T.border}`, borderRadius:12, padding:'16px 18px' }}>
                  <div style={{ fontSize:10, textTransform:'uppercase', letterSpacing:'0.15em', color:T.faint, fontWeight:600, marginBottom:14 }}>Prochains matchs</div>
                  {[
                    { date:'A venir', event:'IEM Atlanta 2026', opp:'Playoffs', note:'En cours' },
                    { date:'Juin 2026', event:'IEM Cologne 2026', opp:'TBD', note:'S-Tier' },
                    { date:'Juil 2026', event:'PGL Major 2026', opp:'TBD', note:'Major' },
                  ].map((m, i) => (
                    <div key={i} style={{ display:'flex', alignItems:'center', gap:10, padding:'8px 0', borderBottom: i < 2 ? `1px solid ${T.border}` : 'none' }}>
                      <div style={{ width:32, height:32, borderRadius:6, background:`${BRAND.amber}22`, border:`1px solid ${BRAND.amber}44`, display:'flex', alignItems:'center', justifyContent:'center', fontSize:'0.7rem', color:BRAND.amber, flexShrink:0 }}>▶</div>
                      <div style={{ flex:1, minWidth:0 }}>
                        <div style={{ fontSize:'0.82rem', fontWeight:600, color:T.text }}>{m.opp}</div>
                        <div style={{ fontSize:'0.68rem', color:T.faint }}>{m.event}</div>
                      </div>
                      <div style={{ fontSize:'0.65rem', background:T.surf3, border:`1px solid ${T.border}`, borderRadius:4, padding:'2px 7px', color:T.dim, flexShrink:0 }}>{m.note}</div>
                    </div>
                  ))}
                </div>

                {/* Stats rapides */}
                <div style={{ background:T.surf, border:`1px solid ${T.border}`, borderRadius:12, padding:'16px 18px' }}>
                  <div style={{ fontSize:10, textTransform:'uppercase', letterSpacing:'0.15em', color:T.faint, fontWeight:600, marginBottom:14 }}>Stats 2026</div>
                  <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:10 }}>
                    {[
                      { val:'#1', label:'Rang HLTV' },
                      { val:'83%', label:'Win rate 30j' },
                      { val:'5', label:'Titres 2026' },
                      { val:'35', label:'Matchs joués' },
                    ].map((s, i) => (
                      <div key={i} style={{ background:T.surf2, border:`1px solid ${T.border}`, borderRadius:8, padding:'10px 12px' }}>
                        <div style={{ fontSize:'1.2rem', fontWeight:800, color:'#FFDE00' }}>{s.val}</div>
                        <div style={{ fontSize:'0.65rem', color:T.faint, marginTop:3 }}>{s.label}</div>
                      </div>
                    ))}
                  </div>
                </div>

                {/* Titres 2026 */}
                <div style={{ background:T.surf, border:`1px solid ${T.border}`, borderRadius:12, padding:'16px 18px' }}>
                  <div style={{ fontSize:10, textTransform:'uppercase', letterSpacing:'0.15em', color:T.faint, fontWeight:600, marginBottom:12 }}>Titres 2026 🏆</div>
                  {['BLAST Rivals Spring', 'IEM Rio', 'BLAST Rotterdam', 'PGL Cluj-Napoca', 'IEM Krakow'].map((t, i) => (
                    <div key={i} style={{ display:'flex', alignItems:'center', gap:8, padding:'5px 0' }}>
                      <span style={{ color:'#FFDE00', fontSize:'0.8rem' }}>★</span>
                      <span style={{ fontSize:'0.78rem', color:T.dim }}>{t}</span>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* TAB BAR */}
      <div style={{ background:T.surf2, borderBottom:`1px solid ${T.border}`, display:'flex', padding:'0 20px', overflowX:'auto' }}>
        {TABS.map(t => (
          <button key={t.id} onClick={()=>setTab(t.id)} style={{
            background:'none', border:'none',
            borderBottom: tab===t.id ? `3px solid ${BRAND.yellow}` : '3px solid transparent',
            color: tab===t.id ? T.text : T.dim,
            fontWeight: tab===t.id ? 600 : 400,
            fontSize:'0.95rem', padding:'14px 20px 11px', letterSpacing:'0.02em',
            cursor:'pointer', whiteSpace:'nowrap', transition:'all 0.15s', fontFamily:'inherit',
          }}>
            {t.label}
          </button>
        ))}
      </div>

      {/* CONTENT */}
      <div style={{ maxWidth:960, margin:'0 auto', padding:'20px 16px 100px' }}>
        {error && <ErrMsg msg={error} T={T} />}

        {/* NEWS */}
        {tab==='news' && (
          loading ? <Spinner label="Generation des actualites du jour..." T={T} /> :
          news.length ? (
            <div>
              <div style={{ fontSize:9, textTransform:'uppercase', letterSpacing:'0.18em', color:T.faint, marginBottom:16, paddingBottom:10, borderBottom:`1px solid ${T.border}` }}>
                Actualites du secteur - {news.length} articles · {dateStr}
              </div>
              <HeroCard item={news[0]} T={T} />
              <div style={{ display:'grid', gridTemplateColumns:'repeat(auto-fill,minmax(260px,1fr))', gap:14 }}>
                {news.slice(1).map((item,i) => <NewsCard key={i} item={item} img={IMG[(i+1)%IMG.length]} i={i} T={T} />)}
              </div>
            </div>
          ) : <ErrMsg msg="Impossible de charger les actualites." T={T} />
        )}

        {/* INSTAGRAM */}
        {tab==='instagram' && (() => {
          const INSTA_GROUPS = [
            {label:'Tous',        cats:null},
            {label:'Materiel',    cats:['Materiel']},
            {label:'Cafes',       cats:['Cafe']},
            {label:'Torrefacteurs', cats:['Torrefacteur']},
            {label:'Producteurs', cats:['Producteur']},
            {label:'Baristas',    cats:['Barista']},
            {label:'The',         cats:['The']},
            {label:'Communaute',  cats:['Communaute','Association','Evenement','Competition','Culture']},
            {label:'Media',       cats:['Media','Education','Formation','Science','Tech']},
            {label:'Boutiques',   cats:['Boutique','Importateur','Packaging','Industrie']},
          ]
          const filtered = instaFilter === 'Tous'
            ? INSTAGRAM
            : INSTAGRAM.filter(a => {
                const grp = INSTA_GROUPS.find(g => g.label === instaFilter)
                return grp && grp.cats && grp.cats.includes(a.category)
              })
          return (
            <div>
              {/* Sub-filter bar */}
              <div style={{ display:'flex', gap:6, flexWrap:'wrap', marginBottom:16, paddingBottom:14, borderBottom:`1px solid ${T.border}` }}>
                {INSTA_GROUPS.map(g => {
                  const count = g.cats === null ? INSTAGRAM.length : INSTAGRAM.filter(a => g.cats.includes(a.category)).length
                  const active = instaFilter === g.label
                  return (
                    <button key={g.label} onClick={() => setInstaFilter(g.label)} style={{
                      background: active ? BRAND.amber : T.surf2,
                      border: `1px solid ${active ? BRAND.amber : T.border2}`,
                      color: active ? '#000' : T.dim,
                      fontSize:'0.75rem', fontWeight: active ? 700 : 400,
                      padding:'5px 13px', borderRadius:20,
                      cursor:'pointer', fontFamily:'inherit', transition:'all 0.15s',
                      display:'flex', alignItems:'center', gap:5,
                    }}>
                      {g.label}
                      <span style={{ fontSize:'0.65rem', opacity:0.7 }}>{count}</span>
                    </button>
                  )
                })}
              </div>
              {/* Count */}
              <div style={{ fontSize:11, textTransform:'uppercase', letterSpacing:'0.12em', color:T.dim, fontWeight:600, marginBottom:14 }}>
                {filtered.length} compte{filtered.length > 1 ? 's' : ''} · {instaFilter}
              </div>
              {/* Grid */}
              <div style={{ display:'grid', gridTemplateColumns:'repeat(auto-fill,minmax(255px,1fr))', gap:12 }}>
                {filtered.map((acc,i) => <InstaCard key={acc.handle} account={acc} i={i} T={T} />)}
              </div>
            </div>
          )
        })()}

        {/* REDDIT */}
        {tab==='reddit' && (
          commLoading ? <Spinner label="Chargement de la communaute..." T={T} /> :
          community.length ? (
            <div>
              <div style={{ fontSize:11, textTransform:'uppercase', letterSpacing:'0.15em', color:T.dim, fontWeight:600, marginBottom:16, paddingBottom:12, borderBottom:`1px solid ${T.border}` }}>
                Communaute · The Sprudge Report · {community.length} articles · {dateStr}
              </div>
              <div style={{ display:'grid', gridTemplateColumns:'repeat(auto-fill,minmax(300px,1fr))', gap:14 }}>
                {community.map((post,i) => <RedditCard key={i} post={post} i={i} T={T} />)}
              </div>
            </div>
          ) : <ErrMsg msg="Impossible de charger le contenu Sprudge." T={T} />
        )}

        {/* SCIENCE */}
        {tab==='science' && (
          loading ? <Spinner label="Recherche d articles scientifiques..." T={T} /> :
          science.length ? (
            <div>
              <div style={{ fontSize:11, textTransform:'uppercase', letterSpacing:'0.15em', color:T.dim, fontWeight:600, marginBottom:16, paddingBottom:12, borderBottom:`1px solid ${T.border}` }}>
                Articles scientifiques - {science.length} articles · 2025-2026
              </div>
              <div style={{ display:'flex', flexDirection:'column', gap:10 }}>
                {science.map((item,i) => <SciCard key={i} item={item} img={SCI_IMG[i%SCI_IMG.length]} i={i} T={T} />)}
              </div>
            </div>
          ) : <ErrMsg msg="Impossible de charger les articles scientifiques." T={T} />
        )}


        {/* TEAM VITALITY */}


        {/* MUSIQUE */}
        {tab==='music' && (
          <div>
            <div style={{ fontSize:11, textTransform:'uppercase', letterSpacing:'0.15em', color:T.dim, fontWeight:600, marginBottom:20, paddingBottom:12, borderBottom:`1px solid ${T.border}` }}>
              Musique · GaufreGentille · {PLAYLISTS.length} playlists sur Suno
            </div>
            <div style={{ display:'grid', gridTemplateColumns:'repeat(auto-fill,minmax(280px,1fr))', gap:16 }}>
              {PLAYLISTS.map((pl, i) => (
                <a key={i} href={pl.url} target="_blank" rel="noopener noreferrer" style={{ textDecoration:'none' }}>
                  <div style={{
                    background:T.surf, border:`1px solid ${T.border}`,
                    borderRadius:14, overflow:'hidden', cursor:'pointer',
                    transition:'all 0.22s',
                    animation:`fadeUp 0.35s ease ${i*100}ms both`,
                  }}
                    onMouseEnter={e=>{ e.currentTarget.style.borderColor=BRAND.amber+'88'; e.currentTarget.style.transform='translateY(-4px)'; e.currentTarget.style.boxShadow=`0 12px 32px rgba(0,0,0,0.3)` }}
                    onMouseLeave={e=>{ e.currentTarget.style.borderColor=T.border; e.currentTarget.style.transform='translateY(0)'; e.currentTarget.style.boxShadow='none' }}
                  >
                    {/* Cover */}
                    <div style={{
                      height:220,
                      backgroundImage:`url(${pl.cover})`,
                      backgroundSize:'cover',
                      backgroundPosition:'center',
                      position:'relative',
                    }}>
                      <div style={{ position:'absolute', inset:0, background:'linear-gradient(to top, rgba(0,0,0,0.75) 0%, transparent 60%)' }} />
                      {/* Play button overlay */}
                      <div style={{
                        position:'absolute', inset:0,
                        display:'flex', alignItems:'center', justifyContent:'center',
                        opacity:0, transition:'opacity 0.2s',
                      }}
                        onMouseEnter={e=>e.currentTarget.style.opacity='1'}
                        onMouseLeave={e=>e.currentTarget.style.opacity='0'}
                      >
                        <div style={{
                          width:56, height:56, borderRadius:'50%',
                          background:BRAND.amber, display:'flex', alignItems:'center', justifyContent:'center',
                          fontSize:'1.4rem', color:'#000',
                        }}>▶</div>
                      </div>
                      {/* Track count badge */}
                      <div style={{
                        position:'absolute', top:12, right:12,
                        background:'rgba(0,0,0,0.6)', backdropFilter:'blur(8px)',
                        borderRadius:20, padding:'3px 10px',
                        fontSize:11, color:'#fff', fontWeight:600,
                      }}>{pl.tracks} tracks</div>
                      {/* Title overlay */}
                      <div style={{ position:'absolute', bottom:14, left:16, right:16 }}>
                        <div style={{ fontSize:'0.65rem', color:BRAND.amber, fontWeight:700, textTransform:'uppercase', letterSpacing:'0.1em', marginBottom:4 }}>GaufreGentille</div>
                        <div style={{ fontFamily:'Georgia,serif', fontSize:'1.3rem', fontWeight:700, color:'#fff', textShadow:'0 2px 8px rgba(0,0,0,0.8)' }}>{pl.name}</div>
                      </div>
                    </div>
                    {/* Footer */}
                    <div style={{ padding:'14px 16px 16px', display:'flex', alignItems:'center', justifyContent:'space-between' }}>
                      <div style={{ fontSize:'0.78rem', color:T.dim, fontStyle:'italic' }}>{pl.vibe}</div>
                      <div style={{
                        display:'inline-flex', alignItems:'center', gap:5,
                        background:BRAND.amber, color:'#000',
                        fontSize:'0.7rem', fontWeight:700,
                        padding:'5px 13px', borderRadius:20, flexShrink:0,
                      }}>▶ Suno</div>
                    </div>
                  </div>
                </a>
              ))}
            </div>
          </div>
        )}

        {/* CA FAIT DU BRUIT */}
        {tab==='gear' && (() => {
          const items = gearItems.length > 0 ? gearItems : gear
          return gearLoading ? <Spinner label="Chargement des nouveautés matériel..." T={T} /> :
          items.length ? (
            <div>
              <div style={{ fontSize:11, textTransform:'uppercase', letterSpacing:'0.15em', color:T.dim, fontWeight:600, marginBottom:16, paddingBottom:12, borderBottom:`1px solid ${T.border}` }}>
                Ça fait du bruit · {items.length} nouveautés · moulins, machines, tasses, drippers...
              </div>
              <GearHeroCard item={items[0]} T={T} />
              <div style={{ display:'grid', gridTemplateColumns:'repeat(auto-fill,minmax(260px,1fr))', gap:14 }}>
                {items.slice(1).map((item,i) => <GearCard key={i} item={item} i={i} T={T} />)}
              </div>
            </div>
          ) : <ErrMsg msg="Impossible de charger les nouveautés." T={T} />
        })()}

      </div>
    </div>
  )
}
